//! mesh-benchmark — measures REAL per-layer standing wave coverage
//! against a loaded .knot, then reports both the measured numbers and
//! the bandwidth/routing speedup those numbers imply for a distributed
//! mesh deploy.
//!
//! Replaces the prior stub (a calculator with hardcoded coverage=0.30
//! that never touched a model). This binary:
//!   1. Loads a real .knot via mmap.
//!   2. Runs N forward passes on the local station.
//!   3. Reads `pipeline.standing_wave_metrics_get(layer_idx)` for each
//!      layer.
//!   4. Reports MEASURED coverage per layer, the bandwidth-saved bytes
//!      that follow from compressing layer outputs to those k dims, and
//!      the d/k ratio that bounds the routing speedup for a multi-hop
//!      mesh deploy.
//!
//! What this does NOT measure (be honest about it):
//!   - Wall-clock latency of a real two-station compressed handoff. That
//!     lives in `parity-station-handoff` (which does the wire round-trip
//!     but does not yet A/B with-vs-without compression).
//!   - Within-layer compute speedup from `resonant_ffn`. The reported
//!     "speedup" here is the ROUTING speedup (d/k bytes per hop), not
//!     end-to-end inference speedup.
//!
//! Usage:
//!   mesh-benchmark \
//!     --knot /tmp/qwen-coder-7b.knot \
//!     --tokens 1,2,3,4,5,6,7,8 \
//!     [--summary-jsonl /tmp/mesh-benchmark-summary.jsonl]

use std::env;
use std::fs::OpenOptions;
use std::io::Write;
use std::time::{Instant, SystemTime, UNIX_EPOCH};

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;

struct Args {
    knot_path: String,
    tokens: Vec<u32>,
    summary_jsonl: Option<String>,
}

fn parse_args() -> Result<Args, String> {
    let argv: Vec<String> = env::args().collect();
    let mut knot_path: Option<String> = None;
    let mut tokens: Option<Vec<u32>> = None;
    let mut summary_jsonl: Option<String> = None;

    let mut i = 1;
    while i < argv.len() {
        match argv[i].as_str() {
            "--knot" => {
                i += 1;
                knot_path = Some(argv.get(i).ok_or("--knot needs a value")?.clone());
            }
            "--tokens" => {
                i += 1;
                let raw = argv.get(i).ok_or("--tokens needs a value")?;
                let parsed: Vec<u32> = raw
                    .split(',')
                    .map(|s| {
                        s.trim()
                            .parse::<u32>()
                            .map_err(|e| format!("bad token {:?}: {}", s, e))
                    })
                    .collect::<Result<_, _>>()?;
                tokens = Some(parsed);
            }
            "--summary-jsonl" => {
                i += 1;
                summary_jsonl = Some(argv.get(i).ok_or("--summary-jsonl needs a value")?.clone());
            }
            other => return Err(format!("unknown arg: {}", other)),
        }
        i += 1;
    }

    Ok(Args {
        knot_path: knot_path.ok_or("--knot is required")?,
        tokens: tokens.ok_or("--tokens is required")?,
        summary_jsonl,
    })
}

fn main() -> Result<(), String> {
    let args = parse_args().inspect_err(|_| {
        eprintln!("usage: mesh-benchmark --knot PATH --tokens IDS [--summary-jsonl PATH]");
    })?;

    println!("============================================================");
    println!(" mesh-benchmark");
    println!("   knot   : {}", args.knot_path);
    println!("   tokens : {} ids", args.tokens.len());
    println!("============================================================");

    // Load real model
    let t = Instant::now();
    let knot = KnotWeights::load(&args.knot_path).map_err(|e| format!("knot load: {:?}", e))?;
    println!("[load] {} ms", t.elapsed().as_millis());

    let t = Instant::now();
    let mut pipeline = NativeLlamaPipeline::from_knot(knot, false, 0.8);
    // Signature extraction is opt-in now that serving skips it by default.
    pipeline.set_standing_wave_extract(true);
    println!("[build pipeline] {} ms", t.elapsed().as_millis());

    let hidden_dim = pipeline.hidden_dim();
    let num_layers = pipeline.num_layers();
    println!(
        "[config] hidden_dim={} num_layers={}",
        hidden_dim, num_layers
    );

    // Run real forward passes
    let mut per_step_ms: Vec<u128> = Vec::with_capacity(args.tokens.len());
    for (step, &token) in args.tokens.iter().enumerate() {
        let t_step = Instant::now();
        pipeline
            .forward_one(token as usize, step, false)
            .map_err(|e| format!("forward_one(step={}): {}", step, e))?;
        let ms = t_step.elapsed().as_millis();
        per_step_ms.push(ms);
        println!("[step {}] forward={} ms (token={})", step, ms, token);
    }

    // Aggregate per-layer measurements from the FINAL pipeline state
    println!();
    println!("Per-layer MEASURED coverage and IMPLIED routing speedup:");
    println!(
        "{:>5} {:>10} {:>10} {:>10} {:>14}",
        "layer", "k_dims", "coverage", "speedup", "saved_bytes/tok"
    );
    println!("{}", "-".repeat(60));

    let mut layers_with_metrics = 0usize;
    let mut sum_coverage = 0.0f64;
    let mut sum_speedup = 0.0f64;
    let mut sum_saved_bytes_per_token = 0u64;
    let mut min_coverage = f64::INFINITY;
    let mut max_coverage = 0.0f64;
    let mut per_layer_summaries: Vec<(usize, f32, f32, usize)> = Vec::new();

    for layer_idx in 0..num_layers {
        if let Some(m) = pipeline.standing_wave_metrics_get(layer_idx) {
            // standing_count is encoded in compressed_size_bytes / 4 (f32) / batch_size.
            // CompressionMetrics stores total bytes; per-token bytes-saved = saved / batch.
            let k_dims = if m.compression_ratio > 0.0 {
                (hidden_dim as f32 * m.compression_ratio) as usize
            } else {
                0
            };
            let saved_per_token = if !args.tokens.is_empty() {
                m.bandwidth_saved_bytes / args.tokens.len()
            } else {
                m.bandwidth_saved_bytes
            };

            println!(
                "{:>5} {:>10} {:>10.4} {:>10.3} {:>14}",
                layer_idx, k_dims, m.compression_ratio, m.estimated_speedup, saved_per_token
            );

            layers_with_metrics += 1;
            sum_coverage += m.compression_ratio as f64;
            sum_speedup += m.estimated_speedup as f64;
            sum_saved_bytes_per_token += saved_per_token as u64;
            min_coverage = min_coverage.min(m.compression_ratio as f64);
            max_coverage = max_coverage.max(m.compression_ratio as f64);
            per_layer_summaries.push((layer_idx, m.compression_ratio, m.estimated_speedup, k_dims));
        }
    }

    println!();
    if layers_with_metrics == 0 {
        return Err(
            "no per-layer metrics populated. extract_and_record_standing_waves \
             may not have run (seq_len=0?) or the pipeline kind doesn't expose \
             standing_wave_metrics_get."
                .to_string(),
        );
    }

    let mean_coverage = sum_coverage / layers_with_metrics as f64;
    let mean_speedup = sum_speedup / layers_with_metrics as f64;
    let mean_step_ms = if !per_step_ms.is_empty() {
        per_step_ms.iter().sum::<u128>() / per_step_ms.len() as u128
    } else {
        0
    };

    println!("============================================================");
    println!(" Summary ({} layers measured)", layers_with_metrics);
    println!("============================================================");
    println!(
        " Coverage (k/d):       mean={:.4}  min={:.4}  max={:.4}",
        mean_coverage, min_coverage, max_coverage
    );
    println!(
        " Routing speedup d/k:  mean={:.3}x  (bytes saved / hop, NOT compute speedup)",
        mean_speedup
    );
    println!(
        " Bandwidth saved:      {} bytes/token (sum over all layers)",
        sum_saved_bytes_per_token
    );
    println!(
        " Forward latency:      mean={} ms/token  (single station, no mesh hop)",
        mean_step_ms
    );

    // Optional: append summary JSONL row for downstream aggregation
    if let Some(path) = args.summary_jsonl {
        let ts = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map(|d| d.as_secs())
            .unwrap_or(0);
        let row = format!(
            "{{\"ts\":{},\"knot\":\"{}\",\"hidden_dim\":{},\"num_layers\":{},\"layers_with_metrics\":{},\"mean_coverage\":{:.6},\"min_coverage\":{:.6},\"max_coverage\":{:.6},\"mean_speedup\":{:.6},\"mean_forward_ms\":{},\"saved_bytes_per_token\":{},\"tokens_run\":{}}}\n",
            ts,
            args.knot_path.replace('"', "\\\""),
            hidden_dim,
            num_layers,
            layers_with_metrics,
            mean_coverage,
            min_coverage,
            max_coverage,
            mean_speedup,
            mean_step_ms,
            sum_saved_bytes_per_token,
            args.tokens.len(),
        );
        let mut f = OpenOptions::new()
            .create(true)
            .append(true)
            .open(&path)
            .map_err(|e| format!("open summary jsonl: {}", e))?;
        f.write_all(row.as_bytes())
            .map_err(|e| format!("write summary: {}", e))?;
        println!(" Summary appended to:  {}", path);
    }

    println!();
    println!("Note: speedup reported is the ratio of inter-layer message size");
    println!("(d floats vs k floats). Wall-clock end-to-end speedup of a");
    println!("multi-station mesh requires running parity-station-handoff with");
    println!("the compressed-routing branch enabled — this binary measures the");
    println!("input to that calculation, not its output.");

    Ok(())
}
